. "$PSScriptRoot\..\Common.ps1"
try{ Require-Admin; $s=Read-Settings; $group='AllowInteractiveLogon'; if(-not(Get-LocalGroup -Name $group -ErrorAction SilentlyContinue)){New-LocalGroup -Name $group -Description '允许本机交互式登录白名单组'|Out-Null}; foreach($u in @($s.AllowedDomainUsers)){try{Add-LocalGroupMember -Group $group -Member $u -ErrorAction Stop}catch{}}; New-Result -Step '02_LoginRestriction' -Enabled $true -Status '已创建/更新本地登录白名单组；避免锁死，未自动写入拒绝登录 SID' -Evidence @{Group=$group; Members=$s.AllowedDomainUsers} }catch{ New-Result -Step '02_LoginRestriction' -Success $false -Status '启用失败' -ErrorMessage $_.Exception.Message }